  const value = clean(input[label]);
  if (!value && !required) return;
  if (type === "number") { const n = Number(value); if (!Number.isNaN(n)) body[name] = n; return; }
  if (type === "boolean") { body[name] = value === "true" || value === "1" || value.toLowerCase() === "yes"; return; }
  body[name] = value;
}
